SELECT 'task' AS type, t.task_name AS title, t.due_date AS evDate, t.task_id AS refId FROM task t WHERE t.project_id = #{projectId} AND t.due_date BETWEEN DATE(#{start}) AND DATE(#{end})
UNION ALL
SELECT 'meet' AS type, m.title AS title, m.meet_date AS evDate, m.meeting_id AS refId FROM meeting m WHERE m.project_id = #{projectId} AND m.meet_date BETWEEN #{start} AND #{end}
